int main() {
    vector<int> v = {5, 3, 8, 1, 9, 2, 7};

    // Full range — most common in contests
    sort(v.begin(), v.end());         // [1,2,3,5,7,8,9]

    // Partial range — sort only indices [2, 5)
    sort(v.begin() + 2, v.begin() + 5); // sort positions 2,3,4

    // Raw arrays work identically
    int arr[] = {4, 2, 6, 1, 3};
    int n = 5;
