    // begin()/end() free functions work on arrays too
    sort(begin(arr), end(arr));

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    vector<int> v = {5, 3, 8, 1, 9};

    // 1. Default ascending
    sort(v.begin(), v.end());
    // v = {1, 3, 5, 8, 9}

    // 2. Descending — use greater<int>() functor
    sort(v.begin(), v.end(), greater<int>());
    // v = {9, 8, 5, 3, 1}

    // 3. Lambda comparator — sort by absolute value
    sort(v.begin(), v.end(), [](int a, int b) {
        return abs(a) < abs(b);
    });

    // 4. Sorting pairs — by second element, break ties by first
    vector<pair<int,int>> p = {{1,5},{3,2},{2,5},{4,1}};
    sort(p.begin(), p.end(), [](auto& a, auto& b) {
        if (a.second != b.second) return a.second < b.second;
        return a.first < a.first;
    });
    // p = {{4,1},{3,2},{1,5},{2,5}}

    // 5. Sorting structs
    struct Task { int deadline, profit; };
    vector<Task> tasks = {{3,100},{1,50},{2,200}};
    sort(tasks.begin(), tasks.end(), [](const Task& a, const Task& b) {
        return a.deadline < b.deadline;  // earliest deadline first
    });

    return 0;
}

