#include <bits/stdc++.h>
using namespace std;

int main() {
    vector<int> v = {1, 3, 3, 3, 5, 7, 9};
    //              0  1  2  3  4  5  6

    // --- Basic usage ---
    auto lo = lower_bound(v.begin(), v.end(), 3);
    auto hi = upper_bound(v.begin(), v.end(), 3);

    cout << "First 3 at index: " << (lo - v.begin()) << "\n"; // 1
    cout << "Last  3 at index: " << (hi - v.begin() - 1) << "\n"; // 3
    cout << "Count of 3: "       << (hi - lo) << "\n"; // 3

    // --- Existence check ---
    if (lo != v.end() && *lo == 3)
        cout << "3 exists\n";

    // --- Floor and Ceil ---
    // Floor(x): largest element <= x
    int x = 4;
    auto it = lower_bound(v.begin(), v.end(), x);
    if (it != v.begin()) {
        --it;
        cout << "Floor of " << x << ": " << *it << "\n"; // 3
    }

    // Ceil(x): smallest element >= x
    it = lower_bound(v.begin(), v.end(), x);
    if (it != v.end())
        cout << "Ceil of " << x << ": " << *it << "\n"; // 5

    // --- Index arithmetic shortcut ---
    int idx = lower_bound(v.begin(), v.end(), 5) - v.begin();
    cout << "Index of first element >= 5: " << idx << "\n"; // 4

    // --- On sorted arrays ---
    int arr[] = {2, 4, 6, 8, 10};
    int n = 5;
    int pos = lower_bound(arr, arr + n, 6) - arr;
    cout << "6 is at index " << pos << "\n"; // 2

    return 0;
}

