#include <bits/stdc++.h>
using namespace std;

int main() {
    vector<int> v = {1, 2, 3, 4, 5};

    // --- Sum ---
    int s = accumulate(v.begin(), v.end(), 0);
    cout << s << "\n"; // 15

    // --- DANGER: Integer overflow when summing large values ---
    // Use 0LL (long long init) to avoid overflow!
    long long bigsum = accumulate(v.begin(), v.end(), 0LL);

    // --- Product ---
    int prod = accumulate(v.begin(), v.end(), 1, multiplies<int>());
    cout << prod << "\n"; // 120

    // --- Max element via fold ---
    int mx = accumulate(v.begin(), v.end(), INT_MIN,
        [](int a, int b) { return max(a, b); });
    cout << mx << "\n"; // 5

    // --- Count elements satisfying condition ---
    int cnt_even = accumulate(v.begin(), v.end(), 0,
        [](int acc, int x) { return acc + (x % 2 == 0 ? 1 : 0); });
    cout << cnt_even << "\n"; // 2

    // --- String join ---
    vector<string> words = {"cp", "is", "fun"};
    string joined = accumulate(next(words.begin()), words.end(), words[0],
        [](const string& a, const string& b) { return a + " " + b; });
    cout << joined << "\n"; // "cp is fun"

    return 0;
}

