int main() {
    int n = 5;
    vector<int> data = {40, 10, 30, 50, 20};

    // Build index array [0,1,2,3,4]
    vector<int> idx(n);
    iota(idx.begin(), idx.end(), 0);  // idx = {0,1,2,3,4}

    // Indirect sort: sort indices by data values
    sort(idx.begin(), idx.end(), [&](int a, int b) {
        return data[a] < data[b];
    });
    // idx = {1,4,2,0,3}  (i.e., data sorted: 10,20,30,40,50)

    for (int i : idx)
        cout << data[i] << " ";  // 10 20 30 40 50
    cout << "\n";

    // Union-Find parent initialisation
    vector<int> parent(n);
    iota(parent.begin(), parent.end(), 0); // parent[i] = i

    return 0;
}

