using namespace std;

int main() {
    vector<int> v = {3, 1, 4, 1, 5, 9, 2};
    vector<int> prefix(v.size());

    // partial_sum writes cumulative sums to output range
    partial_sum(v.begin(), v.end(), prefix.begin());
    // prefix = {3, 4, 8, 9, 14, 23, 25}

    // Range sum query [l, r] (0-indexed)
    auto range_sum = [&](int l, int r) {
        return prefix[r] - (l > 0 ? prefix[l-1] : 0);
    };
    cout << range_sum(2, 5) << "\n"; // 4+1+5+9 = 19

    // In-place prefix sum (overwrites original)
    partial_sum(v.begin(), v.end(), v.begin());

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    // --- Basic usage ---
    vector<int> v = {1, 2, 3};
    do {
        for (int x : v) cout << x << " ";
        cout << "\n";
    } while (next_permutation(v.begin(), v.end()));
    // Prints all 6 permutations in lex order

    cout << "---\n";

    // --- Contest pattern: try all permutations, track best ---
    int n;
    cin >> n;
    vector<int> perm(n);
    iota(perm.begin(), perm.end(), 1);  // {1,2,...,n}

    int ans = INT_MIN;
    do {
        // Evaluate some objective on this permutation
        int score = 0;
        for (int i = 0; i < n - 1; i++)
            score += abs(perm[i] - perm[i+1]);  // example: sum of adjacent diffs
        ans = max(ans, score);
    } while (next_permutation(perm.begin(), perm.end()));

    cout << ans << "\n";

    // --- ONLY feasible for n <= 8 (8! = 40320) ---
    // For n <= 10 it's borderline, n >= 12 will TLE.

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    vector<int> v = {4, 7, 2, 9, 1, 5, 3};

    // --- find: returns iterator to first match, or end() if not found ---
    auto it = find(v.begin(), v.end(), 9);
    if (it != v.end())
        cout << "Found 9 at index " << (it - v.begin()) << "\n"; // 3

    // --- find_if: find first element satisfying predicate ---
    auto first_gt5 = find_if(v.begin(), v.end(), [](int x) { return x > 5; });
    if (first_gt5 != v.end())
        cout << "First > 5: " << *first_gt5 << "\n"; // 7

    // --- count: number of occurrences ---
    cout << count(v.begin(), v.end(), 7) << "\n"; // 1

    // --- count_if: count elements satisfying predicate ---
    int evens = count_if(v.begin(), v.end(), [](int x) { return x % 2 == 0; });
    cout << "Even count: " << evens << "\n"; // 2

    // --- all_of, any_of, none_of ---
    bool all_pos  = all_of(v.begin(),  v.end(), [](int x) { return x > 0; }); // true
    bool any_neg  = any_of(v.begin(),  v.end(), [](int x) { return x < 0; }); // false
    bool none_neg = none_of(v.begin(), v.end(), [](int x) { return x < 0; }); // true

    cout << all_pos << " " << any_neg << " " << none_neg << "\n"; // 1 0 1

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    vector<int> v = {1, 2, 3, 4, 5};

    // --- transform: apply function to each element ---
    vector<int> sq(v.size());
    transform(v.begin(), v.end(), sq.begin(), [](int x) { return x * x; });
    // sq = {1, 4, 9, 16, 25}

    // transform with TWO input ranges (element-wise operation)
    vector<int> a = {1,2,3}, b = {4,5,6}, res(3);
    transform(a.begin(), a.end(), b.begin(), res.begin(), plus<int>());
    // res = {5, 7, 9}

    // --- fill and fill_n ---
    vector<int> dp(10);
    fill(dp.begin(), dp.end(), -1);    // all -1
    fill_n(dp.begin(), 5, 0);          // first 5 = 0

    // --- reverse ---
    reverse(v.begin(), v.end());       // {5,4,3,2,1}

    // --- rotate: bring middle to front ---
    // rotate(first, new_first, last)
    vector<int> r = {1,2,3,4,5};
    rotate(r.begin(), r.begin() + 2, r.end());
    // r = {3,4,5,1,2}  (shift left by 2)

    // --- unique: remove CONSECUTIVE duplicates (sort first!) ---
    vector<int> u = {1,1,2,3,3,3,4};
    auto new_end = unique(u.begin(), u.end());
    u.erase(new_end, u.end());
    // u = {1,2,3,4}

    return 0;
}

