#include <bits/stdc++.h>
using namespace std;

int main() {
    vector<int> a = {1, 2, 3, 4, 5};
    vector<int> b = {3, 4, 5, 6, 7};
    // Both must be sorted!

    vector<int> u, inter, diff, sdiff;

    // Union
    set_union(a.begin(), a.end(), b.begin(), b.end(), back_inserter(u));
    // u = {1,2,3,4,5,6,7}

    // Intersection
    set_intersection(a.begin(), a.end(), b.begin(), b.end(), back_inserter(inter));
    // inter = {3,4,5}

    // Difference (a - b)
    set_difference(a.begin(), a.end(), b.begin(), b.end(), back_inserter(diff));
    // diff = {1,2}

    // Symmetric difference (elements in one but not both)
    set_symmetric_difference(a.begin(), a.end(), b.begin(), b.end(), back_inserter(sdiff));
    // sdiff = {1,2,6,7}

    // includes: does a contain all elements of b?
    bool contained = includes(a.begin(), a.end(), inter.begin(), inter.end());
    cout << contained << "\n"; // 1 (true)

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    vector<int> v = {1, 2, 3, 4, 5, 6, 7, 8};

    // partition: evens before odds (order within groups not preserved)
    auto mid = partition(v.begin(), v.end(), [](int x) { return x % 2 == 0; });
    // [evens | odds], mid points to first odd element

    cout << "Evens: ";
    for (auto it = v.begin(); it != mid; ++it)
        cout << *it << " ";
    cout << "\nOdds: ";
    for (auto it = mid; it != v.end(); ++it)
        cout << *it << " ";
    cout << "\n";

    // stable_partition: same but preserves relative order
    vector<int> v2 = {1,2,3,4,5,6};
    stable_partition(v2.begin(), v2.end(), [](int x) { return x % 2 == 0; });
    // v2 = {2,4,6,1,3,5}  (original order preserved within groups)

    // partition_point: binary search for partition boundary (O(log n))
    // (v2 must be partitioned by the predicate)
    auto pp = partition_point(v2.begin(), v2.end(), [](int x) { return x % 2 == 0; });
    cout << "First odd: " << *pp << "\n"; // 1

    return 0;
}

