// Given n meetings with start and end times, find the minimum number
// of meeting rooms required to hold all meetings simultaneously.
// Constraints: 1 <= n <= 1e5, 0 <= start < end <= 1e9
//
// Example:
// Input:  n=3, meetings = {(0,30),(5,10),(15,20)}
// Output: 2
// Explanation: Room 1 hosts (0,30); Room 2 hosts (5,10) then (15,20)

sections.solution:
#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<int> starts(n), ends(n);
    for (int i = 0; i < n; i++)
        cin >> starts[i] >> ends[i];

    sort(starts.begin(), starts.end());
    sort(ends.begin(), ends.end());

    int rooms = 0, maxRooms = 0;
    int e = 0; // pointer into ends[]

    for (int i = 0; i < n; i++) {
        if (starts[i] < ends[e]) {
            // New meeting starts before earliest ongoing meeting ends
            rooms++;
        } else {
            // Reuse a room (an existing meeting has finished)
            e++;
        }
        maxRooms = max(maxRooms, rooms);
    }

    cout << maxRooms << "\n";
    return 0;
}

