// Coordinate Compression:
// Given n values (possibly large, up to 1e9), compress them to
// the range [0, k-1] where k is the number of distinct values.
// Relative order must be preserved.
//
// Input:  n=6, values = {400, 100, 200, 100, 400, 300}
// Output compressed: {3, 0, 1, 0, 3, 2}
//
// This is a critical pre-processing step for BIT/segment tree problems
// where you need array indices but values are huge.

sections.solution:
#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<int> a(n);
    for (auto& x : a) cin >> x;

    // Step 1: Build sorted unique value list (the 'dictionary')
    vector<int> sorted_unique = a;
    sort(sorted_unique.begin(), sorted_unique.end());
    sorted_unique.erase(
        unique(sorted_unique.begin(), sorted_unique.end()),
        sorted_unique.end()
    );
    // sorted_unique = {100, 200, 300, 400}

    // Step 2: Compress each value to its rank
    vector<int> compressed(n);
    for (int i = 0; i < n; i++) {
        compressed[i] = lower_bound(
            sorted_unique.begin(),
            sorted_unique.end(),
            a[i]
        ) - sorted_unique.begin();
    }

    for (int x : compressed)
        cout << x << " ";
    cout << "\n";

    // To decompress: sorted_unique[compressed[i]] == a[i]

    return 0;
}

