// Given an array of n integers, find the length of the Longest
// Non-Decreasing Subsequence (LNDS). The minimum number of deletions
// to make the array non-decreasing = n - LNDS.
//
// Constraints: 1 <= n <= 1e5, 1 <= a[i] <= 1e9
// Input:  n=7, a = {3, 1, 4, 1, 5, 9, 2}
// Output: 4  (LNDS length = 4: e.g. {1,1,5,9} or {1,4,5,9})
//         Deletions = 7 - 4 = 3
//
// This is the Longest Non-Decreasing Subsequence (LIS variant)
// solvable in O(n log n) using patience sorting + upper_bound.

sections.solution:
#include <bits/stdc++.h>
using namespace std;

int lnds(vector<int>& a) {
    vector<int> tails; // tails[i] = smallest tail of LNDS of length i+1
    for (int x : a) {
        // upper_bound for non-decreasing (allows equal)
        // lower_bound for strictly increasing
        auto it = upper_bound(tails.begin(), tails.end(), x);
        if (it == tails.end())
            tails.push_back(x);  // new longer subsequence found
        else
            *it = x;             // replace: smaller tail is always better
    }
    return tails.size();
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<int> a(n);
    for (auto& x : a) cin >> x;

    int ans = lnds(a);
    cout << "LNDS length: " << ans << "\n";
    cout << "Min deletions: " << (n - ans) << "\n";

    return 0;
}
